#include <omp.h>
#include <stdio.h>
#include <iostream>
#include <fstream>
#include <stdlib.h>
#include <sys/time.h>
#include <string.h>
#include <assert.h>
#include <math.h>
#include <sys/resource.h>
#include <limits.h>

using namespace std;

/* this structure represents a point */
/* these will be passed around to avoid copying coordinates */
typedef struct {
  float weight;
  float *coord;
  long assign;  /* number of point where this one is assigned */
  float cost;  /* cost of that assignment, weight*distance */
} Point;

/* this is the array of points */
typedef struct {
  long num; /* number of points; may not be N if this is a sample */
  int dim;  /* dimensionality */
  Point *p; /* the array itself */
} Points;

//=======================================
// Euclidean Distance
//=======================================
float d_dist(int p1, int p2, int num, int dim, float *coord) {
  float retval = 0.0;
  for(int i = 0; dim > i; i++){
    float tmp = coord[(i*num)+p1] - coord[(i*num)+p2];
    retval = retval + (tmp * tmp);
  }
  return retval;
}

//=======================================
// Kernel - Compute Cost
//=======================================
void kernel_compute_cost(int num, int dim, long x, Point *p, int K, int stride,
                         float *coord, float *work_mem, int *center_table, bool *switch_membership) {
  int tid = omp_get_thread_num();
  if(num > tid) {
    float *lower = &work_mem[tid*stride];

    // cost between this point and point[x]: euclidean distance multiplied by weight
    float x_cost = d_dist(tid, x, num, dim, coord) * p[tid].weight;

    // if computed cost is less then original (it saves), mark it as to reassign
    if (p[tid].cost > x_cost) {
      switch_membership[tid] = 1;
      lower[K] += x_cost - p[tid].cost;
    }
    // if computed cost is larger, save the difference
    else {
      lower[center_table[p[tid].assign]] += p[tid].cost - x_cost;
    }
  }
}

//=======================================
// pgain Entry - OMP SETUP + OMP CALL
//=======================================
float pgain(long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center, int *center_table, bool *switch_membership, bool isCoordChanged,
            double *serial_t, double *cpu_to_gpu_t, double *gpu_to_cpu_t, double *alloc_t, double *kernel_t, double *free_t) {
  int stride = *numcenters + 1;            // size of each work_mem segment
  int K = *numcenters;                       // number of centers
  int num = points->num;                       // number of points
  int dim = points->dim;                     // number of dimension
  int nThread = num;                         // number of threads == number of data points

  //=========================================
  // ALLOCATE HOST MEMORY + DATA PREPARATION
  //=========================================
  float *work_mem = (float *) malloc(stride * (nThread + 1) * sizeof(float));
  float *coord = (float *) malloc(num * dim * sizeof(float));

  // build center-index table
  int count = 0;
  for (int i = 0; num > i; i++) {
    if (is_center[i]) {
      center_table[i] = count++;
    }
  }

  // Extract 'coord'
  // Only if first iteration OR coord has changed
  if (isCoordChanged) {
    for (int i = 0; dim > i; i++) {
      for (int j = 0; num > j; j++) {
        coord[(num * i) + j] = points->p[j].coord[i];
      }
    }
  }

  //=======================================
  // CPU (SERIAL) WORK
  //=======================================
  int number_of_centers_to_close = 0;
  float gl_cost_of_opening_x = z;
  float *gl_lower = &work_mem[stride * nThread];
  // compute the number of centers to close if we are to open i
  for (int i = 0; num > i; i++) {
    if (is_center[i]) {
      float low = z;
      for (int j = 0; num > j; j++) {
        low = low + (work_mem[j * stride + center_table[i]]);
      }

      gl_lower[center_table[i]] = low;

      if (0 < low) {
        ++number_of_centers_to_close;
        work_mem[i * stride + K] -= low;
      }
    }
    gl_cost_of_opening_x = gl_cost_of_opening_x + (work_mem[i * stride + K]);
  }

  //if opening a center at x saves cost (i.e. cost is negative) do so; otherwise, do nothing
  if (0 > gl_cost_of_opening_x) {
    for (int i = 0; num > i; i++) {
      bool close_center = 0 < gl_lower[center_table[points->p[i].assign]];
      if (switch_membership[i] || close_center) {
        points->p[i].cost = d_dist(points->p[i].assign, x, num, dim, coord) * points->p[i].weight;
        points->p[i].assign = x;
      }
    }

    for (int i = 0; num > i; i++) {
      if (is_center[i] && 0 < gl_lower[center_table[i]]) {
        is_center[i] = false;
      }
    }

    if (0 <= x && num > x) {
      is_center[x] = true;
    }
    *numcenters = *numcenters + 1 - number_of_centers_to_close;
  } else {
    gl_cost_of_opening_x = 0;
  }

  free(work_mem);
  free(coord);
  return -gl_cost_of_opening_x;
}

int main() {
  // Initialize variables and data structures
  int num = 1000;
  int dim = 10;
  int K = 5;
  float z = 1.0;
  float *coord = (float *) malloc(num * dim * sizeof(float));
  Point *points = (Point *) malloc(num * sizeof(Point));
  bool *is_center = (bool *) malloc(num * sizeof(bool));
  int *center_table = (int *) malloc(num * sizeof(int));
  bool *switch_membership = (bool *) malloc(num * sizeof(bool));
  long int numcenters = K; // declare numcenters as long int

  // Initialize OpenMP
  omp_set_num_threads(4);

  // Call pgain function
  double serial_t = 0.0;
  double cpu_to_gpu_t = 0.0;
  double gpu_to_cpu_t = 0.0;
  double alloc_t = 0.0;
  double kernel_t = 0.0;
  double free_t = 0.0;
  pgain(0, (Points *) points, z, &numcenters, K, is_center, center_table, switch_membership, true,
        &serial_t, &cpu_to_gpu_t, &gpu_to_cpu_t, &alloc_t, &kernel_t, &free_t);

  // Clean up
  free(coord);
  free(points);
  free(is_center);
  free(center_table);
  free(switch_membership);

  return 0;
}
